def compute(inputs):
    tax_liability = inputs['tax_liability']
    tax_credit = inputs['tax_credit']
    refundable = inputs['refundable']
    if tax_liability < 0 or tax_credit < 0:
        raise ValueError('Tax liability and tax credit must be non-negative values.')
    if refundable:
        remaining_liability = tax_liability - tax_credit
    else:
        remaining_liability = max(0, tax_liability - tax_credit)
    return remaining_liability

def compute(inputs):
    closing_price = inputs['closing_price']
    subscription_price = inputs['subscription_price']
    rights_ratio = inputs['rights_ratio']
    adjusted_price = (closing_price + subscription_price * rights_ratio) / (1 + rights_ratio)
    return round(adjusted_price, 2)

def compute(inputs):
    current_gdp = inputs['current_gdp']
    previous_gdp = inputs['previous_gdp']
    if previous_gdp == 0:
        raise ValueError('Previous GDP must not be zero.')
    gdp_growth_rate = (current_gdp - previous_gdp) / previous_gdp * 100
    return round(gdp_growth_rate, 2)

def compute(inputs):
    itemized_deductions = inputs['itemized_deductions']
    standard_deduction = inputs['standard_deduction']
    tax_bracket = inputs['tax_bracket']
    if itemized_deductions > standard_deduction:
        tax_benefit = (itemized_deductions - standard_deduction) * tax_bracket
    else:
        tax_benefit = 0.0
    return round(tax_benefit, 2)

def compute(inputs):
    prices = inputs['prices']
    weights = inputs['weights']
    weighted_index = sum((price * weight for price, weight in zip(prices, weights)))
    return round(weighted_index, 2)

def compute(inputs):
    nominal_values = inputs['nominal_values']
    months_since_origination = inputs['months_since_origination']
    if len(nominal_values) != len(months_since_origination):
        raise ValueError('The length of nominal_values and months_since_origination must be the same.')
    total_value = sum(nominal_values)
    if total_value == 0:
        raise ValueError('The total value of nominal values must be greater than zero.')
    weighted_sum = sum((value * months for value, months in zip(nominal_values, months_since_origination)))
    wala = weighted_sum / total_value
    return round(wala, 2)

def compute(inputs):
    trade_value = inputs['trade_value']
    pip_size = inputs['pip_size']
    exchange_rate = inputs.get('exchange_rate')
    if exchange_rate is not None:
        pip_value = trade_value * (pip_size / exchange_rate)
    else:
        pip_value = trade_value * pip_size
    return round(pip_value, 2)

def compute(inputs):
    cost = inputs['cost']
    useful_life = inputs['useful_life']
    method = inputs.get('method', 'straight_line')
    if useful_life <= 0:
        raise ValueError('Useful life must be a positive integer.')
    if method not in {'straight_line', 'double_declining_balance'}:
        raise ValueError("Method must be either 'straight_line' or 'double_declining_balance'.")
    if method == 'straight_line':
        depreciation = cost / useful_life
    elif method == 'double_declining_balance':
        depreciation = cost * 2 / useful_life
    return round(depreciation)
